    **수정할 코드 (위의 기존 코드를 다음으로 대체):**
    ```javascript
    // 시스템 프롬프트와 사용자 프로필 컨텍스트를 결합하여 모델에게 전달
    // 이 로직은 시스템 프롬프트가 적용되는 방식과 유사하게, 대화의 가장 초기에 모델에게 정보를 전달합니다.
    const initialUserMessageContent = [];
    if (userProfileContext) {
        initialUserMessageContent.push(userProfileContext);
    }
    if (systemPrompt && systemPrompt.trim() !== '') {
        initialUserMessageContent.push(systemPrompt.trim());
    }

    if (initialUserMessageContent.length > 0 && conversationHistory.length === 1 && conversationHistory[0].role === 'user') {
        // 새 대화 시작 시에만 시스템 프롬프트와 프로필 정보를 결합하여 추가
        historyForAI.unshift(
            { role: 'user', parts: [{ type: 'text', text: initialUserMessageContent.join('\n\n') }] },
            { role: 'model', parts: [{ type: 'text', text: '알겠습니다. 당신의 지시와 정보를 참고하여 응답하겠습니다.' }] }
        );
    }
